VALUES
  ('public-health-specialist-moex-01277', 'public-health-specialist', 'public-health-specialist-moex-111-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '下表是一個探討兩種抗血栓藥物（Aspirin,Warfarin）與發生缺血性心臟疾病的隨機對照試驗 研究數據，包含四組治療組：安慰劑、單獨使用Aspirin、單獨使用Warfarin、合併使用Aspirin 及Warfarin，下列敘述何者錯誤？ 治療組別 缺血性心臟疾病發生率/1000人年 Doubleplacebo 13.3 Aspirinalone 10.3 Warfarinalone 10.2 AspirinandWarfarin 8.7', '["單獨使用Aspirin會減少3.0/1000人年的缺血性心臟疾病發生率", "單獨使用Warfarin會減少3.1/1000人年的缺血性心臟疾病發生率", "Aspirin與Warfarin對缺血性心臟疾病風險有加成協同作用", "Aspirin與Warfarin對缺血性心臟疾病風險有加成拮抗作用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:58+00:00", "source_pdf_sha1": "6407aa1bde53", "answer_pdf_sha1": "99abb9d811bf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "110", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
